{
  query(input: {
    connection: { driver: sqlite3, database: "examples/sample.db" }
    from: "users"
    limit: 5
    relations: [{ entity: "posts", foreignKey: "user_id", type: hasMany, select: ["id","title"] }]
  }) { count data }
}

{
  introspect(connection: { driver: sqlite3, database: "examples/sample.db" }) {
    tables { name columns { name type nullable isPrimaryKey } }
  }
}

